from typing import Set, List, Optional

from geosat.cloud import PointCloud

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from psanp.segmentation.ground import smooth_ground_detection


class SmoothGroundClassifier(Classifier):
    def __init__(
        self,
        gsd=0.05,
        max_diff=0.2,
        high_pass_radius=3,
        denoising_radius=3,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.gsd = gsd
        self.max_diff = max_diff
        self.high_pass_radius = high_pass_radius
        self.denoising_radius = denoising_radius
        self.input_class = "ground"
        self.output_class = "smooth_ground"

    def execute_on(self, cloud: PointCloud, pipeline_metadata: PipelineMetadata):
        if not cloud:
            return (cloud,)
        smooth_ground_detection.find_smooth_ground(
            cloud,
            pipeline_metadata.classification_codes[self.input_class],
            pipeline_metadata.classification_codes[self.output_class],
            self.gsd,
            self.max_diff,
            self.high_pass_radius,
            self.denoising_radius,
        )

        return (cloud,)

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option("gsd", "voxel size", type_cast=float, required=False),
            Option("max_diff", "", type_cast=float, required=False),
            Option("high_pass_radius", "", type_cast=int, required=False),
            Option("denoising_radius", "", type_cast=int, required=False),
        ]

    def input_classes(self) -> Set[str]:
        return {self.input_class}

    def output_classes(self) -> Set[str]:
        return {self.output_class}
